NMC_fixed_result.T2_base = T2_base;

% Final action allocation and losses.
NMC_fixed_result.Pred_Action_opt = Pred_Action_opt;
NMC_fixed_result.Action_Ratio_opt = Action_Ratio_opt;
NMC_fixed_result.PerfectInfo_Action_Ratio = PerfectInfo_Action_Ratio;
NMC_fixed_result.True_Action_Ratio = PerfectInfo_Action_Ratio; % legacy alias
NMC_fixed_result.O_arr_opt = O_arr_opt;
NMC_fixed_result.H_arr_opt = H_arr_opt;
