NMC_fixed_result.R_arr_opt = R_arr_opt;
NMC_fixed_result.Total_Loss_opt = Total_Loss_opt;
NMC_fixed_result.Executed_Pathway_Value_opt = Executed_Pathway_Value_opt;
NMC_fixed_result.PerfectInfo_Pathway_Value_opt = PerfectInfo_Pathway_Value_opt;
NMC_fixed_result.Net_Realized_Value_opt = Net_Realized_Value_opt;
NMC_fixed_result.Net_Revenue_opt = Net_Realized_Value_opt; % legacy alias

% NMC net-utility curves.
NMC_fixed_result.s_hat_grid = s_hat_grid;
NMC_fixed_result.G = G;
NMC_fixed_result.G_env = G_env;
NMC_fixed_result.J = J;

% Residual-error template.
NMC_fixed_result.k_emp = k_emp;
