NMC_fixed_result.residual_scaling_definition = ...
 'e_NMC(k) = rho * [e_LFP(k) - mean(e_LFP(k))]';

% A3 recycling decomposition.
NMC_fixed_result.mean_soh_rec = mean_soh_rec;
NMC_fixed_result.A3_recycling_contribution_values = vals_full;
NMC_fixed_result.A3_recycling_contribution_labels = labels_A3;
NMC_fixed_result.A3_net_value = net_value_A3;

save(cfg.result_mat, 'NMC_fixed_result', '-v7.3');

Summary_Table = table( ...
 rho, ...
 opt_k_NMC, ...
